input.chart:
{
  "title": "LTO Performance Comparison: Traffic Lift, Attach Rate & Incrementality",
  "transform": [
    {"fold": ["INCREMENTAL_TRAFFIC_PCT", "ATTACH_RATE", "INCREMENTALITY_SCORE"]},
    {"calculate": "({'INCREMENTAL_TRAFFIC_PCT': 'Incremental Traffic %', 'ATTACH_RATE': 'Attach Rate %', 'INCREMENTALITY_SCORE': 'Incrementality Score'})[datum.key]", "as": "key"}
  ],
  "mark": "bar",
  "encoding": {
    "x": {"field": "value", "title": "Performance Metric Value", "type": "quantitative"},
    "y": {"field": "ITEM_NAME", "title": "LTO Item", "type": "nominal", "sort": "-x"},
    "yOffset": {"field": "key", "type": "nominal"},
    "color": {"field": "key", "title": "Metric", "type": "nominal"}
  }
}
